@ARTICLE{10.1021/acs.jafc.1c02430,
	author = {Gao, J. and Mao, K. and Wang, X. and Mi, S. and Fu, M. and Li, X. and Xiao, J. and Simal-Gandara, J. and Sang, Y.},
	title = {Tibet Kefir Milk Regulated Metabolic Changes Induced by High-Fat Diet via Amino Acids, Bile Acids, and Equol Metabolism in Human-Microbiota-Associated Rats},
	journal = {Journal of Agricultural and Food Chemistry},
	year = {2021},
	abstract = {This study aimed to confirm the effects of Tibet kefir milk (TKM) on gut microbiota and metabolism. An obesity model was established by feeding a high-fat diet (HFD) to human-microbiota-associated rats. Next-generation sequencing and ultrahigh-performance liquid chromatography-quadrupole time-of-flight mass spectrometry were applied for gut microbiota and untargeted metabolomics, respectively. After 8 weeks of feeding, the enterotype in the HFD group was switched from ET1 (Prevotella/Akkermansia-dominant) to ET2 (Bacteroides/Akkermansia-dominant). Branched-chain amino-acids- and aromatic amino-acids-metabolism increased, and taurine-conjugated bile acids decreased in the HFD group. Compared with the HFD group, taurocholic acid increased in the TKM1 group, while l-threonine decreased, and equol, taurochenodeoxycholate, and taurodeoxycholic acid increased in the TKM2 group. The metabolite alteration suggested restorative bile acid metabolism, modified metabolic pattern of amino acids, and elevation of anti-obesity factors in the TKM-intervened animals. It can be deduced that changes by TKM intervention in the host gut metabolites are the major contributors to reducing fat deposition. © ER -},
	doi = {10.1021/acs.jafc.1c02430},
	type = {JOUR}
}

@ARTICLE{10.3390/nu16050680,
	author = {Liu, Y. and Bu, Y. and Cao, J. and Liu, Y. and Zhang, T. and Hao, L. and Yi, H.},
	title = {Effect of Fermented Milk Supplemented with Nisin or Plantaricin Q7 on Inflammatory Factors and Gut Microbiota in Mice},
	journal = {Nutrients},
	year = {2024},
	abstract = {Lactic-acid-bacteria-derived bacteriocins are used as food biological preservatives widely. Little information is available on the impact of bacteriocin intake with food on gut microbiota in vivo. In this study, the effects of fermented milk supplemented with nisin (FM-nisin) or plantaricin Q7 (FM-Q7) from Lactiplantibacillus plantarum Q7 on inflammatory factors and the gut microbiota of mice were investigated. The results showed that FM-nisin or FM-Q7 up-regulated IFN-γ and down-regulated IL-17 and IL-12 in serum significantly. FM-nisin down-regulated TNF-α and IL-10 while FM-Q7 up-regulated them. The results of 16S rRNA gene sequence analysis suggested that the gut microbiome in mice was changed by FM-nisin or FM-Q7. The Firmicutes/Bacteroides ratio was reduced significantly in both groups. It was observed that the volume of Akkermansia_Muciniphila was significantly reduced whereas those of Lachnospiraceae and Ruminococcaceae were increased. The total number of short-chain fatty acids (SCFAs) in the mouse feces of the FM-nisin group and FM-Q7 group was increased. The content of acetic acid was increased while the butyric acid content was decreased significantly. These findings indicated that FM-nisin or FM-Q7 could stimulate the inflammation response and alter gut microbiota and metabolic components in mice. Further in-depth study is needed to determine the impact of FM-nisin or FM-Q7 on the host’s health. © 2024 by the authors. ER -},
	doi = {10.3390/nu16050680},
	type = {JOUR}
}

@ARTICLE{10.3390/nu17050923,
	author = {Hao, L. and Liu, Y. and Szeto, I.M.-Y. and Hao, H. and Zhang, T. and Liu, T. and Yi, H.},
	title = {Milk Exosome-Based Delivery System for Probiotic Encapsulation That Enhances the Gastrointestinal Resistance and Adhesion of Probiotics},
	journal = {Nutrients},
	year = {2025},
	abstract = {The oral administration of probiotics is a promising strategy to regulate the host–intestinal flora balance and improve health. Nevertheless, adverse gastrointestinal (GI) conditions affect the activity of free native probiotics. In this study, a novel probiotic encapsulation system based on milk exosomes (mExos) and DSPE-PEG-PBA was developed. mExos acted as a shield to protect probiotics from harsh GI environments, and DSPE-PEG-PBA served as a bridge between mExos and probiotics. The coated probiotics were characterized by transmission electron microscopy (TEM), Fourier transform infrared spectroscopy (FT-IR), and intrinsic fluorescence spectra. The results showed three probiotics (Akkermansia muciniphila (AKK), Bifidobacterium animalis subsp. lactis BB-12 (BB12), and Lactiplantibacillus plantarum Q7 (Q7)) were coated with mExos@DSPE-PEG-PBA, with encapsulation rates of 90.37 ± 0.45%, 84.47 ± 1.22%, and 70.93 ± 2.39%, respectively. This encapsulation not only preserved the growth activity of the probiotics but also provided robust protection against the detrimental effects of acidic pH, bile salts, and digestive enzymes. The encapsulated strains Q7, BB12, and AKK demonstrated survival rates of 80.99 ± 0.41%, 85.28 ± 0.20%, and 94.53 ± 0.26%, respectively, in an in vitro simulated GI environment. The mExos@DSPE-PEG-PBA-encapsulated probiotics exhibited enhanced hydrophobicity and auto-aggregation capacity, accompanied by a significant improvement in mucoadhesive properties, which collectively potentiated their colonization potential within the gastrointestinal tract. These findings substantiate the potential of mExos as an encapsulation platform for probiotics, providing valuable insights into the selection of exosomes as encapsulating agents to enhance probiotic viability and mucoadhesive capacity. © 2025 by the authors. ER -},
	doi = {10.3390/nu17050923},
	type = {JOUR}
}

@ARTICLE{10.1016/j.lwt.2024.116187,
	author = {Fonseca, M. and Vedor, R. and Barbosa, J.C. and Gomes, A.M. and Machado, D.},
	title = {Can a functional cheese spread incorporating Akkermansia muciniphila deliver beneficial physicochemical and biological properties while enhancing probiotic stability and viability during aerobic storage and in vitro digestion?},
	journal = {LWT},
	year = {2024},
	abstract = {In the present study, next generation probiotic Akkermansia muciniphila was incorporated into a dairy matrix containing Portuguese whey cheese and Greek-style yoghurt in a proportion of 3.5:1, respectively. Subsequently, this innovative food was characterized in terms of microbiological and physicochemical parameters, total phenolic content and antioxidant, antidiabetic, and antihypertensive activities, as well as its protective effect on A. muciniphila viability during 21 d of refrigerated aerobic storage and when subjected to simulated gastrointestinal passage. The probiotic cheese spread displayed high microbiological quality, low total phenolic content (0.36 mg gallic acid equivalents/g of dried cheese) and interesting biological activities, including antidiabetic (98.10% α-glucosidase inhibition) and antihypertensive (49.18% angiotensin converting enzyme inhibition). Simultaneously, this food ensured a high A. muciniphila viability (>108 CFU/g) during 21 d of refrigerated aerobic storage with subsequent in vitro digestion. Additionally, this probiotic cheese presented a similar profile in terms of texture, color, water activity and pH when compared to the cheese control (without A. muciniphila), suggesting a potentially high acceptance among consumers. In conclusion, the developed cheese spread seems to be a promising and suitable food vector to safeguard A. muciniphila viability during refrigerated aerobic storage for at least 21 d with subsequent gastrointestinal passage. © 2024 The Authors ER -},
	doi = {10.1016/j.lwt.2024.116187},
	type = {JOUR}
}

@ARTICLE{10.1016/j.ijbiomac.2023.129152,
	author = {Huang, X. and Liu, R. and Wang, J. and Bao, Y. and Yi, H. and Wang, X. and Lu, Y.},
	title = {Preparation and synbiotic interaction mechanism of microcapsules of Bifidobacterium animalis F1–7 and human milk oligosaccharides (HMO)},
	journal = {International Journal of Biological Macromolecules},
	year = {2024},
	abstract = {Probiotics such as Bifidobacterium spp. generally possess important physiological functions. However, maintaining probiotic viability is a challenge during processing, storage, and digestive transit period. Microencapsulation is widely considered to be an attractive approach. In this study, B. animalis F1–7 microcapsules and B. animalis F1–7-HMO microcapsules were successfully prepared by emulsification/internal gelation with high encapsulation efficiency (90.67 % and 92.16 %, respectively). The current study revealed that HMO-supplemented microcapsules exhibited more stable lyophilized forms and thermal stability. Additionally, a significant improvement in probiotic cell viability was observed in such microcapsules during simulated gastrointestinal (GI) fluids or storage. We also showed that the individual HMO mixtures 6′-SL remarkably promoted the growth and acetate yield of B. animalis F1–7 for 48 h (p < 0.05). The synbiotic combination of 6′-SL with B. animalis F1–7 enhanced SCFAs production in vitro fecal fermentation, decreasing several harmful intestinal bacteria such as Dorea, Escherichia-Shigella, and Streptococcus while enriching the probiotic A. muciniphila. This study provides strong support for HMO or 6′-SL combined with B. animalis F1–7 as an innovative dietary ingredient to bring health benefits. The potential of the synbiotic microcapsules with this combination merits further exploration for future use in the food industry. © 2024 Elsevier B.V. ER -},
	doi = {10.1016/j.ijbiomac.2023.129152},
	type = {JOUR}
}
